local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxSoundMgr:LxBaseMgr
local LxSoundMgr = classX("LxSoundMgr", LxBaseMgr)

local typeofAudioSource = typeof(UnityEngine.AudioSource)

local _SwitchPriorityList = {BgmPlayType.player, BgmPlayType.wnd, BgmPlayType.map}

function LxSoundMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._audioSourceObjList = {}

    local audioTrans = FindObject("RehtGame/NodeAudio").transform
    self._audioTrans = audioTrans

    local audioSourceList = {}
    for k = 1, 16 do
        table.insert(audioSourceList, self:CreateAudioSource(audioTrans, "sound"..k))
    end

    ---@type LxBgm
    self._bgm = require("LApp.component.media.LxBgm"):New(self:CreateAudioSource(audioTrans, "bgm"))
    self._bgm:Initialize()
    ---@type LxSound
    self._solo = require("LApp.component.media.LxSound"):New(self:CreateAudioSource(audioTrans, "solo"))
    self._solo:Initialize()
    ---@type LxSound
    self._feedback = require("LApp.component.media.LxSound"):New(self:CreateAudioSource(audioTrans, "feedback"))
    self._feedback:Initialize()
    ---@type LxSoundGroup
    self._soundGroup = require("LApp.component.media.LxSoundGroup"):New(audioSourceList)
    self._soundGroup:Initialize()

    self:InitVolumes()

    self._bgmDatas = {}
    for k,v in ipairs(_SwitchPriorityList) do
        self._bgmDatas[v] = {}
    end

    self._bEnablePlay = false
end

function LxSoundMgr:Dispose()
    if self._bgm then
        self._bgm:Dispose()
        self._bgm = nil
    end
    if self._soundGroup then
        self._soundGroup:Dispose()
        self._soundGroup = nil
    end
    if self._solo then
        self._solo:Dispose()
        self._solo = nil
    end

    if self._feedback then
        self._feedback:Dispose()
        self._feedback = nil
    end

    if self._audioSourceObjList then
        for k,v in ipairs(self._audioSourceObjList) do
            LxResUtil.DestroyObject(v)
        end
    end
    LxBaseMgr.Dispose(self)
end

---热更重载用
function LxSoundMgr:ClearAllSounds()
    if self._bgm then
        self._bgm:Dispose()
        self._bgm = nil
    end
    if self._soundGroup then
        self._soundGroup:Dispose()
        self._soundGroup = nil
    end
    if self._solo then
        self._solo:Dispose()
        self._solo = nil
    end

    if self._feedback then
        self._feedback:Dispose()
        self._feedback = nil
    end
end

function LxSoundMgr:EnablePlay(bEnable)
    self._bEnablePlay = bEnable
end

function LxSoundMgr:OnUpdate()
    if self._isDisposed then return end
    if not self._bEnablePlay then return end

    if self._isSwitchBGM then
        self._isSwitchBGM = nil
        self:InternalSwitchBGM()
    end
end

function LxSoundMgr:InitVolumes()
    self._bgmVolume = checknumber(LPlayerPrefs.musicVolume)
    self._bgmMute = checkbool(LPlayerPrefs.musicMute)
    self._soundVolume = checknumber(LPlayerPrefs.soundVolume)
    self._soundMute = checkbool(LPlayerPrefs.soundMute)
    self._soloVolume = checknumber(LPlayerPrefs.singleSoundVolume)
    self._soloMute = checkbool(LPlayerPrefs.singleSoundMute)

    if LGameSettings.isNotSound and CS.IsWebGL() then
        self._bgmVolume = 0
        self._bgmMute = nil
        self._soundVolume = 0
        self._soundMute = nil
        self._soloVolume = 0
        self._soloMute = nil
    end

    self._bgm:SetMute(self._bgmMute)
    self._bgm:SetVolume(self._bgmVolume)

    self._soundGroup:SetMute(self._soundMute)
    self._soundGroup:SetVolume(self._soundVolume)
    self._feedback:SetMute(self._soundMute)
    self._feedback:SetVolume(self._soundVolume)

    self._solo:SetMute(self._soloMute)
    self._solo:SetVolume(self._soloVolume)
end

function LxSoundMgr:CreateAudioSource(parentTrans, index)
    local obj = LxResUtil.NewGameObject(tostring(index))
    table.insert(self._audioSourceObjList, obj)
    obj.transform:SetParent(parentTrans, false)
    local audioSource = obj:AddComponent(typeofAudioSource)
    audioSource.playOnAwake = false
    audioSource.loop = false
    return audioSource
end

function LxSoundMgr:InternalSwitchBGM()
    if not self._bgm then return end
    if self._bgmMute then return end

    local bgmData
    local bgmDatas = self._bgmDatas
    local list
    local len = 0
    for k,v in ipairs(_SwitchPriorityList) do
        list = bgmDatas[v]
        len = #list
        if len > 0 then
            bgmData = list[len]
            break
        end
    end
    if not bgmData then return end

    local bgmName = "music/"..bgmData.name
    if bgmName == self._bgm:GetBgmName() then return end

    --self._bgm:StopBgm()
    self._bgmData = bgmData
    self._bgm:PlayBgm(bgmData.name)
end

function LxSoundMgr:AddBgm(playType, bgmName, fromName)
    local list = self._bgmDatas[playType]
    if not list then return end

    local index = 0
    for k,v in ipairs(list) do
        if v.name == bgmName and v.fromName == fromName then
            index = k
        end
    end
    if index > 0 then
        local data = table.remove(list, index)
        table.insert(list, data)
    else
        table.insert(list, {name=bgmName, fromName = fromName})
    end
    self._isSwitchBGM = true
end

function LxSoundMgr:RemoveBgm(playType, bgmName, fromName)
    local list = self._bgmDatas[playType]
    if not list then return end

    local index = 0
    for k,v in ipairs(list) do
        if v.name == bgmName and v.fromName == fromName then
            index = k
        end
    end
    if index > 0 then
        table.remove(list, index)
        self._isSwitchBGM = true
    end
end

---音效播放，以名字的前缀来确定路径
---C_xxx combat
---S_xxx story
---H_xxx hero
---E_xxx effect
---@param audioName
function LxSoundMgr:PlaySound(audioName)
    if self._isDisposed then return end
    if not self._bEnablePlay then return end
    if string.isempty(audioName) then
        LogWarn("LxSoundMgr:PlaySound audioName error!")
        return
    end
    if self:IsShieldSoundName(audioName) then return end

    local playAudio = self._soundGroup
    local audioPath = audioName
    playAudio:PlaySound(audioPath)
end

function LxSoundMgr:PlaySoundByRefId(refId)
    local soundName = LxResPathUtil.GetAudioSoundNameByRefId(refId)
    if soundName then
        return self:PlaySound(soundName)
    end
end

function LxSoundMgr:StopSound()
    if self._isDisposed then return end

    self._soundGroup:StopSound()
end


function LxSoundMgr:SetMusicVolume(vol)
    if self._bgmVolume == vol then return end

    self._bgmVolume = vol
    if self._bgm then 
        self._bgm:SetVolume(vol) 
    end
    LPlayerPrefs.SetMusicVolume(vol)
end

function LxSoundMgr:GetMusicVolume()
    return tonumber(LPlayerPrefs.musicVolume)
end

function LxSoundMgr:SetMusicMute(bMute)
    if self._bgmMute == bMute then return end

    self._bgmMute = bMute
    if self._bgm then
        self._bgm:SetMute(bMute)
    end
    LPlayerPrefs.SetMusicMute(bMute)
    if not bMute then
        self._isSwitchBGM = true
    end
end

function LxSoundMgr:IsMusicMute()
    return toboolean(LPlayerPrefs.musicMute)
end

function LxSoundMgr:SetSoundVolume(vol)
    if self._soundVolume == vol then return end

    self._soundVolume = vol
    if self._soundGroup then 
        self._soundGroup:SetVolume(vol) 
    end
    LPlayerPrefs.SetSoundVolume(vol)
end

function LxSoundMgr:GetSoundVolume()
    return tonumber(LPlayerPrefs.soundVolume)
end

function LxSoundMgr:SetSoundMute(bMute)
    if self._soundMute == bMute then return end

    self._soundMute = bMute
    if self._soundGroup then 
        self._soundGroup:SetMute(bMute) 
    end
    LPlayerPrefs.SetSoundMute(bMute)
end

function LxSoundMgr:IsSoundMute()
    return toboolean(LPlayerPrefs.soundMute)
end


function LxSoundMgr:PlaySingleSound(soundResPath,func)
    if self._isDisposed then return end
    if string.isempty(soundResPath) then return end
    if self:IsShieldSoundName(soundResPath) then return end
    
    self:StopSingleSound()
    self._solo:SetLoadedFunc(func)
    self._solo:PlaySound(soundResPath)
end

function LxSoundMgr:IsShieldSoundName(soundResPath)
    local resType = LPlayerPrefs.GetLocalization()
    if resType and resType == 3 then
        LogWarn("[音频资源屏蔽]  开始对比：" .. soundResPath)
        local lowSoundResPath = string.lower(soundResPath)
        for refId,v in pairs(GameTable.SoundFilternRef) do
            if v.type == 1 then
                if lowSoundResPath == refId then
                    return true
                end
            else
                if string.find(lowSoundResPath,refId) then
                    return true
                end
            end
        end
    end
    return false
end

function LxSoundMgr:StopSingleSound()
    if self._isDisposed then return end

    self._solo:StopPlay()
end

function LxSoundMgr:IsSingleSoundPlaying()
    if self._isDisposed then return false end

    return self._solo:IsPlaying()
end

function LxSoundMgr:SetSingleSoundVolume(vol)
    if self._soloVolume == vol then return end

    self._soloVolume = vol
    if self._solo then 
        self._solo:SetVolume(vol) 
    end
    LPlayerPrefs.SetSingleSoundVolume(vol)
end

function LxSoundMgr:SetSingleSoundMute(bMute)
    if self._soloMute == bMute then return end

    self._soloMute = bMute
    if self._solo then 
        self._solo:SetMute(bMute) 
    end
    LPlayerPrefs.SetSingleSoundMute(bMute)
end

function LxSoundMgr:GetSingleSoundVolume()
    return tonumber(LPlayerPrefs.singleSoundVolume)
end

function LxSoundMgr:IsSingleSoundMute()
    return toboolean(LPlayerPrefs.singleSoundMute)
end

function LxSoundMgr:PauseForVideo(bPause)
    if self._bgm then
        self._bgm:PauseForVideo(bPause)
    end
end

---------------------------------------------------
function LxSoundMgr:OnPlayWndMusic(musicName, wndName)
    if self._isDisposed then return end

    self:AddBgm(BgmPlayType.wnd, musicName, wndName)
end

function LxSoundMgr:OnCloseWndMusic(wndName)
    if self._isDisposed then return end

    self:RemoveBgm(BgmPlayType.wnd, nil, wndName)
end

function LxSoundMgr:OnPauseWndMusic(wndName, bPause)
    if self._isDisposed then return end
    if not self._bgm or not self._bgmData then return end

    if self._bgmData.fromName == wndName then
        self._bgm:PauseBgm(bPause or false and true)
    end
end

function LxSoundMgr:PlayMapMusic(musicName, surroundList, bOnce)
    if self._isDisposed then return end

    local bSurround = surroundList and #surroundList > 0
    bOnce = bSurround and bOnce or false
    if bSurround or not string.isempty(musicName) then
        self:AddBgm(BgmPlayType.map, musicName, "scene", surroundList, bOnce)
    end
end

function LxSoundMgr:CloseAllMusic()
    if self._bgm then
        self._bgm:StopBgm()
    end
end

function LxSoundMgr:SetWndMusicPlayTime(time)
    if self._isDisposed then return end

    self._bgm:SetPlayTime(time)
end

function LxSoundMgr:GetWndMusicPlayTime(wndName)
    if self._isDisposed then return end

    if not self._bgmData or not self._bgm then return 0 end

    if self._bgmData.fromName == wndName then
        return self._bgm:GetPlayTime()
    else
        return 0
    end
end

function LxSoundMgr:GetWndMusicLength(wndName)
    if self._isDisposed then return end

    if not self._bgmData or not self._bgm then return 0 end

    if self._bgmData.fromName == wndName then
        return self._bgm:GetMusicLength()
    else
        return 0
    end
end

function LxSoundMgr:IsWndMusicPlaying(wndName)
    if self._isDisposed then return false end

    if not self._bgmData or not self._bgm then return false end

    if self._bgmData.fromName == wndName then
        return self._bgm:IsPlaying()
    else
        return false
    end
end

function LxSoundMgr:IsWndMusicReady(wndName)
    if self._isDisposed then return false end

    if not self._bgmData or not self._bgm then return false end

    if self._bgmData.fromName == wndName then
        return self._bgm:IsReady()
    else
        return false
    end
end

function LxSoundMgr:SetTempVolume(value)
    if self._isDisposed then return end
    
    self._bgm:SetVolume(value)
end

function LxSoundMgr:CancelTempVolume()
    self:SetMusicVolume(tonumber(LPlayerPrefs.musicVolume))
end


return LxSoundMgr